// Runtime generator that builds flashcards from the qbank and formula imports
const DOMAIN_NAMES: Record<number, string> = {
  0: 'Mathematics', 1: 'Probability & Statistics', 2: 'Ethics & Professional Practice',
  3: 'Engineering Economics', 4: 'Electrical Materials', 5: 'Engineering Sciences',
  6: 'Circuit Analysis DC & AC', 7: 'Linear Systems', 8: 'Signal Processing',
  9: 'Electronics', 10: 'Power Systems', 11: 'Electromagnetics',
  12: 'Control Systems', 13: 'Communications', 14: 'Computer Networks',
  15: 'Digital Systems', 16: 'Computer Systems', 17: 'Software Development',
};

function difficultyToCategory(d: number): string {
  return d === 1 ? 'definition' : d === 2 ? 'concept' : 'formula';
}

// Build remaining flashcards for topics 8-17
let nextId = FEEE_FLASHCARDS.length + 1;

// Add question-based flashcards for topics 8-17
for (const q of FE_EE_QUESTIONS) {
  if (q.topicId < 8) continue; // topics 0-7 already inline
  const correctText = q.options[q.correct];
  FEEE_FLASHCARDS.push({
    id: nextId++,
    front: q.question,
    back: `${correctText} — ${q.explanation}`,
    domain: `topic${q.topicId}`,
    domainName: DOMAIN_NAMES[q.topicId],
    category: difficultyToCategory(q.difficulty),
    topics: [q.subtopic],
  });
}

// Add formula-based flashcards for topics 8-17
for (const sheet of FE_EE_FORMULA_SHEETS) {
  if (sheet.topicId < 8) continue; // topics 0-7 already inline
  for (const f of sheet.formulas) {
    FEEE_FLASHCARDS.push({
      id: nextId++,
      front: `What is ${f.name}?`,
      back: `${f.formula} — ${f.notes}`,
      domain: `topic${sheet.topicId}`,
      domainName: DOMAIN_NAMES[sheet.topicId],
      category: 'formula',
      topics: [sheet.title],
    });
  }
}

// Update the count after generation
FEEE_FLASHCARD_COUNT = FEEE_FLASHCARDS.length;

export function getFEEEFlashcards(domain?: string): FEEEFlashcard[] {
  if (!domain) return FEEE_FLASHCARDS;
  return FEEE_FLASHCARDS.filter(c => c.domain === domain);
}
